import React from 'react';
import "./ToDoList.css";
import ToDoFormAdd from './ToDoFormAdd';
import Filters from './Filters';

const ToDoList = () => {
    return (
        <div className='container-todo'>
            <h1>TODO List</h1>

            <ToDoFormAdd/>

            <div className="todo">
                <Filters/>

                <div className="list">
                    
                </div>
            </div>
        </div>
    );
}

export default ToDoList;
